mapper.select:
SELECT fa.`иҙҰжҲ·зј–еҸ·` AS accountId, fa.`иҙҰжҲ·зј–з Ғ` AS accountCode, fa.`иҙҰжҲ·еҗҚз§°` AS accountName, fa.`иҙҰжҲ·зұ»еһӢ` AS accountType, fa.`иҙҰжҲ·й“¶иЎҢиҙҰеҸ·` AS accountBankAccount, fa.`иҙҰжҲ·й“¶иЎҢжңәжһ„` AS accountBankInstitution, fa.`жҳҜеҗҰеҗҜз”Ё` AS enabled, fa.`еӨҮжіЁ` AS remark, fa.`еҲӣе»әж—¶й—ҙ` AS createTime, fa.`жӣҙж–°ж—¶й—ҙ` AS updateTime, e1.`е‘ҳе·Ҙе§“еҗҚ` AS createUserName, e2.`е‘ҳе·Ҙе§“еҗҚ` AS updateUserName, fo.`з»„з»ҮеҗҚз§°` AS organizationName, 0 AS displayOrder, fa.`еҲӣе»әдәәзј–з Ғ` AS creatorId FROM FUND_ACCOUNT fa LEFT JOIN EMPLOYEE e1 ON fa.`еҲӣе»әдәәзј–з Ғ` = e1.`е‘ҳе·Ҙзј–з Ғ` LEFT JOIN EMPLOYEE e2 ON fa.`жӣҙж–°дәәзј–з Ғ` = e2.`е‘ҳе·Ҙзј–з Ғ` LEFT JOIN FUND_ORGANIZATION fo ON fa.`з»„з»Үзј–еҸ·` = fo.`з»„з»Үзј–еҸ·`
fa.`з»„з»Үзј–еҸ·` = #{organizationId}
AND fa.`иҙҰжҲ·еҗҚз§°` LIKE CONCAT('%', #{query.accountName}, '%')
AND fa.`иҙҰжҲ·зұ»еһӢ` = #{query.accountType}
AND fa.`жҳҜеҗҰеҗҜз”Ё` = #{query.isEnabled}
AND fa.`еҲӣе»әдәәзј–з Ғ` = #{query.creatorFilter}
ORDER BY fa.`иҙҰжҲ·еҗҚз§°` ASC
